  const users = [
    { id: 1, name: "Adithya", age: 20 },
    { id: 2, name: "Doraemon", age: 12},
    { id: 3, name: "Shinchan", age: 5}
  ]

  return (
    <div className="App">
      {users.map((user, key) => {
        return <div key={key}>UserID : {user.id}, Name : {user.name}, Age : {user.age}</div>
      })}
    </div>
  );
}

